urlset:
{{- $baseUrl := site.BaseURL -}}
{{- range .Site.AllPages -}}
  {{- if and (not .Params.private) (in (slice "page" "home" "section" "taxonomy" "term") .Kind) -}}

  {{ .Permalink }}
  {{- if not .Lastmod.IsZero }}
  {{ safeHTML ( .Lastmod.Format "2006-01-02T15:04:05+07:00" ) }}
  {{- else if not .PublishDate.IsZero }}
  {{ safeHTML ( .PublishDate.Format "2006-01-02T15:04:05+07:00" ) }}
  {{- end }}
  {{- if .Params.changefreq }}
  {{ .Params.changefreq }}
  {{- else }}
  monthly
  {{- end }}
  {{- if gt .Weight 0 }}
  {{ mul (div .Weight 100) 0.8 | printf "%.1f" }}
  {{- else }}
  0.5
  {{- end }}
  {{- if .Params.cover.image }}

    {{ .Params.cover.image | absURL }}

  {{- end }}

  {{- end -}}
{{- end }}
